+import { describe, it, expect, beforeEach } from 'vitest';
+import { EventBus } from '../../src/events/event-bus.js';
+import {
+  NotificationService,
+  resetNotificationIdCounter,
+} from '../../src/services/notification.service.js';
+import { PreferencesService } from '../../src/services/preferences.service.js';
+import {
+  NotificationHistoryService,
+  resetLogIdCounter,
+} from '../../src/services/notification-history.service.js';
+import { EmailAdapter, InMemoryTransport } from '../../src/adapters/email.adapter.js';
+import { SmsAdapter, InMemorySmsTransport } from '../../src/adapters/sms.adapter.js';
+import {
+  WebhookAdapter,
+  InMemoryWebhookTransport,
+} from '../../src/adapters/webhook.adapter.js';
+import type {
+  OrderCreatedEvent,
+  OrderStatusChangedEvent,
+  UserCreatedEvent,
+} from '../../src/events/event-types.js';
+
+/**
+ * Integration tests for the full notification pipeline.
+ *
+ * These tests wire up the complete stack:
+ *   EventBus → NotificationService → Adapters (email/sms/webhook)
+ *                                   → PreferencesService
+ *                                   → NotificationHistoryService
+ *
+ * Unlike unit tests, nothing is mocked — we use the in-memory transports
+ * provided by each adapter to verify actual delivery.
+ */
+describe('Notification Pipeline Integration', () => {
+  let eventBus: EventBus;
+  let notificationService: NotificationService;
+  let preferencesService: PreferencesService;
+  let historyService: NotificationHistoryService;
+  let emailTransport: InMemoryTransport;
+  let smsTransport: InMemorySmsTransport;
+  let webhookTransport: InMemoryWebhookTransport;
+
+  beforeEach(() => {
+    eventBus = new EventBus();
+    notificationService = new NotificationService(eventBus);
+    preferencesService = new PreferencesService();
+    historyService = new NotificationHistoryService();
+    resetNotificationIdCounter();
+    resetLogIdCounter();
+
+    // Wire up preferences and history
+    notificationService.setPreferencesService(preferencesService);
+    notificationService.setHistoryService(historyService);
+
+    // Set up email adapter with in-memory transport
+    emailTransport = new InMemoryTransport();
+    const emailAdapter = new EmailAdapter(
+      { from: 'noreply@taskflow.com', appName: 'TaskFlow Pro' },
+      emailTransport,
+    );
+    notificationService.registerAdapter(emailAdapter);
+
+    // Set up SMS adapter with in-memory transport
+    smsTransport = new InMemorySmsTransport();
+    const smsAdapter = new SmsAdapter(
+      { fromNumber: '+15551234567' },
+      smsTransport,
+    );
+    notificationService.registerAdapter(smsAdapter);
+
+    // Set up webhook adapter with in-memory transport
+    webhookTransport = new InMemoryWebhookTransport();
+    const webhookAdapter = new WebhookAdapter(
+      { url: 'https://hooks.example.com/notify', secret: 'test-secret' },
+      webhookTransport,
+    );
+    notificationService.registerAdapter(webhookAdapter);
+  });
+
+  // -- Helpers --
+
+  function makeUser(overrides?: Partial<OrderCreatedEvent['user']>) {
+    return {
+      id: 'user-1',
+      name: 'Alice',
+      email: 'alice@example.com',
+      role: 'member' as const,
+      createdAt: new Date(),
+      updatedAt: new Date(),
+      ...overrides,
+    };
+  }
+
+  function makeOrder(overrides?: Partial<OrderCreatedEvent['order']>) {
+    return {
+      id: 'order-1',
+      userId: 'user-1',
+      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
+      total: 20,
+      status: 'pending' as const,
+      createdAt: new Date(),
+      updatedAt: new Date(),
+      ...overrides,
+    };
+  }
+
+  // =========================================================
+  // 1. Email channel — end-to-end via EventBus
+  // =========================================================
+
+  describe('email channel end-to-end', () => {
+    it('should deliver email when user has email preferences enabled', async () => {
+      const user = makeUser();
+
+      // Default preferences have email enabled
+      preferencesService.updatePreferences(user.id, { emailEnabled: true });
+
+      const event: UserCreatedEvent = {
+        type: 'user:created',
+        user,
+        timestamp: new Date(),
+      };
+
+      await eventBus.emit(event);
+
+      // Verify email was delivered via transport
+      const inbox = emailTransport.getInbox();
+      expect(inbox).toHaveLength(1);
+      expect(inbox[0]?.to).toBe('alice@example.com');
+      expect(inbox[0]?.subject).toBe('Welcome to TaskFlow Pro');
+      expect(inbox[0]?.html).toContain('Welcome');
+
+      // Verify notification was recorded in service
+      const notifications = notificationService.getNotifications();
+      expect(notifications).toHaveLength(1);
+      expect(notifications[0]?.status).toBe('sent');
+      expect(notifications[0]?.type).toBe('user-welcome');
+
+      // Verify history was logged
+      const logs = historyService.getAll();
+      expect(logs).toHaveLength(1);
+      expect(logs[0]?.status).toBe('sent');
+      expect(logs[0]?.channel).toBe('email');
+      expect(logs[0]?.recipient).toBe('alice@example.com');
+    });
+
+    it('should deliver order confirmation email with correct content', async () => {
+      const user = makeUser();
+      const order = makeOrder();
+
+      const event: OrderCreatedEvent = {
+        type: 'order:created',
+        order,
+        user,
+        timestamp: new Date(),
+      };
+
+      await eventBus.emit(event);
+
+      const inbox = emailTransport.getInbox();
+      expect(inbox).toHaveLength(1);
+      expect(inbox[0]?.subject).toContain('Order Confirmation');
+      // HTML template should include order details
+      expect(inbox[0]?.html).toContain('Order Confirmation');
+
+      const logs = historyService.getAll();
+      expect(logs).toHaveLength(1);
+      expect(logs[0]?.type).toBe('order-confirmation');
+      expect(logs[0]?.status).toBe('sent');
+    });
+
+    it('should deliver order status update emails', async () => {
+      const event: OrderStatusChangedEvent = {
+        type: 'order:status-changed',
+        order: makeOrder({ status: 'confirmed', userId: 'alice@example.com' }),
+        previousStatus: 'pending',
+        newStatus: 'confirmed',
+        timestamp: new Date(),
+      };
+
+      await eventBus.emit(event);
+
+      const inbox = emailTransport.getInbox();
+      expect(inbox).toHaveLength(1);
+      expect(inbox[0]?.subject).toContain('Order Update');
+
+      const notifications = notificationService.getNotifications();
+      expect(notifications[0]?.type).toBe('order-status-update');
+      expect(notifications[0]?.status).toBe('sent');
+    });
+  });
+
+  // =========================================================
+  // 2. SMS channel — end-to-end via direct send
+  // =========================================================
+
+  describe('SMS channel end-to-end', () => {
+    it('should deliver SMS notification to user with SMS preferences enabled', async () => {
+      preferencesService.updatePreferences('user-1', {
+        channelEnabled: { sms: true },
+      });
+
+      await notificationService.sendNotification(
+        'order-confirmation',
+        {
+          recipient: '+15559876543',
+          subject: 'Order Confirmation: order-1',
+          body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
+          channel: 'sms',
+          priority: 'normal',
+          metadata: { orderId: 'order-1', userId: 'user-1' },
+        },
+        'user-1',
+      );
+
+      // Verify SMS was delivered via transport
+      const sent = smsTransport.getSent();
+      expect(sent).toHaveLength(1);
+      expect(sent[0]?.to).toBe('+15559876543');
+      expect(sent[0]?.body).toContain('Order Confirmation');
+      expect(sent[0]?.body).toContain('Widget x2');
+
+      // Verify history logged
+      const logs = historyService.getAll();
+      expect(logs).toHaveLength(1);
+      expect(logs[0]?.status).toBe('sent');
+      expect(logs[0]?.channel).toBe('sms');
+    });
+
+    it('should block SMS when user disables SMS channel', async () => {
+      preferencesService.updatePreferences('user-1', {
+        channelEnabled: { sms: false },
+      });
+
+      await notificationService.sendNotification(
+        'order-confirmation',
+        {
+          recipient: '+15559876543',
+          subject: 'Order Confirmation',
+          body: 'Your order has been placed.',
+          channel: 'sms',
+          priority: 'normal',
+        },
+        'user-1',
+      );
+
+      // SMS should NOT be delivered
+      expect(smsTransport.getSent()).toHaveLength(0);
+
+      // History should log as skipped
+      const logs = historyService.getAll();
+      expect(logs).toHaveLength(1);
+      expect(logs[0]?.status).toBe('skipped');
+      expect(logs[0]?.channel).toBe('sms');
+    });
+  });
+
+  // =========================================================
+  // 3. Webhook channel — end-to-end via direct send
+  // =========================================================
+
+  describe('webhook channel end-to-end', () => {
+    it('should deliver webhook notification', async () => {
+      await notificationService.sendNotification(
+        'order-status-update',
+        {
+          recipient: 'system-hook',
+          subject: 'Order Update: order-1',
+          body: 'Order status changed to shipped.',
+          channel: 'webhook',
+          priority: 'normal',
+          metadata: { orderId: 'order-1', newStatus: 'shipped' },
+        },
+        'user-1',
+      );
+
+      // Verify webhook was posted
+      const requests = webhookTransport.getRequests();
+      expect(requests).toHaveLength(1);
+      expect(requests[0]?.url).toBe('https://hooks.example.com/notify');
+      expect(requests[0]?.body.subject).toBe('Order Update: order-1');
+      expect(requests[0]?.body.body).toContain('shipped');
+      expect(requests[0]?.headers['X-Webhook-Secret']).toBe('test-secret');
+
+      // Verify history
+      const logs = historyService.getAll();
+      expect(logs).toHaveLength(1);
+      expect(logs[0]?.status).toBe('sent');
+      expect(logs[0]?.channel).toBe('webhook');
+    });
+
+    it('should block webhook when user disables webhook channel', async () => {
+      preferencesService.updatePreferences('user-1', {
+        channelEnabled: { webhook: false },
+      });
+
+      await notificationService.sendNotification(
+        'order-status-update',
+        {
+          recipient: 'system-hook',
+          subject: 'Order Update',
+          body: 'Status changed.',
+          channel: 'webhook',
+          priority: 'normal',
+        },
+        'user-1',
+      );
+
+      expect(webhookTransport.getRequests()).toHaveLength(0);
+
+      const logs = historyService.getAll();
+      expect(logs).toHaveLength(1);
+      expect(logs[0]?.status).toBe('skipped');
+    });
+  });
+
+  // =========================================================
+  // 4. Preferences enforcement
+  // =========================================================
+
+  describe('preferences enforcement across channels', () => {
+    it('should block email when email is disabled', async () => {
+      const user = makeUser();
+      preferencesService.updatePreferences(user.id, { emailEnabled: false });
+
+      await eventBus.emit<UserCreatedEvent>({
+        type: 'user:created',
+        user,
+        timestamp: new Date(),
+      });
+
+      // No email should be sent
+      expect(emailTransport.getInbox()).toHaveLength(0);
+
+      // Notification should NOT appear in the service's list
+      expect(notificationService.getNotifications()).toHaveLength(0);
+
+      // History should log as skipped
+      const logs = historyService.getAll();
+      expect(logs).toHaveLength(1);
+      expect(logs[0]?.status).toBe('skipped');
+    });
+
+    it('should block notification when category is unsubscribed', async () => {
+      const user = makeUser();
+      preferencesService.updatePreferences(user.id, {
+        categorySubscriptions: { 'order-confirmation': false },
+      });
+
+      await eventBus.emit<OrderCreatedEvent>({
+        type: 'order:created',
+        order: makeOrder(),
+        user,
+        timestamp: new Date(),
+      });
+
+      expect(emailTransport.getInbox()).toHaveLength(0);
+
+      const logs = historyService.getAll();
+      expect(logs).toHaveLength(1);
+      expect(logs[0]?.status).toBe('skipped');
+    });
+
+    it('should block email when frequency is not immediate', async () => {
+      const user = makeUser();
+      preferencesService.updatePreferences(user.id, {
+        emailFrequency: 'daily-digest',
+      });
+
+      await eventBus.emit<UserCreatedEvent>({
+        type: 'user:created',
+        user,
+        timestamp: new Date(),
+      });
+
+      expect(emailTransport.getInbox()).toHaveLength(0);
+
+      const logs = historyService.getAll();
+      expect(logs).toHaveLength(1);
+      expect(logs[0]?.status).toBe('skipped');
+    });
+
+    it('should allow SMS when email is disabled (channels are independent)', async () => {
+      preferencesService.updatePreferences('user-1', {
+        emailEnabled: false,
+        channelEnabled: { sms: true },
+      });
+
+      // Email should be blocked via event
+      await eventBus.emit<UserCreatedEvent>({
+        type: 'user:created',
+        user: makeUser(),
+        timestamp: new Date(),
+      });
+      expect(emailTransport.getInbox()).toHaveLength(0);
+
+      // SMS should still work
+      await notificationService.sendNotification(
+        'user-welcome',
+        {
+          recipient: '+15559876543',
+          subject: 'Welcome',
+          body: 'Welcome to TaskFlow Pro!',
+          channel: 'sms',
+          priority: 'normal',
+        },
+        'user-1',
+      );
+      expect(smsTransport.getSent()).toHaveLength(1);
+    });
+  });
+
+  // =========================================================
+  // 5. History logging
+  // =========================================================
+
+  describe('notification history', () => {
+    it('should log all notification attempts with correct details', async () => {
+      const user = makeUser();
+
+      // Send two different notifications
+      await eventBus.emit<OrderCreatedEvent>({
+        type: 'order:created',
+        order: makeOrder(),
+        user,
+        timestamp: new Date(),
+      });
+      await eventBus.emit<UserCreatedEvent>({
+        type: 'user:created',
+        user,
+        timestamp: new Date(),
+      });
+
+      const logs = historyService.getAll();
+      expect(logs).toHaveLength(2);
+
+      // First log: order confirmation
+      expect(logs[0]?.type).toBe('order-confirmation');
+      expect(logs[0]?.channel).toBe('email');
+      expect(logs[0]?.status).toBe('sent');
+      expect(logs[0]?.recipient).toBe('alice@example.com');
+
+      // Second log: welcome
+      expect(logs[1]?.type).toBe('user-welcome');
+      expect(logs[1]?.channel).toBe('email');
+      expect(logs[1]?.status).toBe('sent');
+    });
+
+    it('should support querying history by recipient', async () => {
+      const alice = makeUser();
+      const bob = makeUser({ id: 'user-2', name: 'Bob', email: 'bob@example.com' });
+
+      await eventBus.emit<UserCreatedEvent>({
+        type: 'user:created',
+        user: alice,
+        timestamp: new Date(),
+      });
+      await eventBus.emit<UserCreatedEvent>({
+        type: 'user:created',
+        user: bob,
+        timestamp: new Date(),
+      });
+
+      const aliceLogs = historyService.getByRecipient('alice@example.com');
+      expect(aliceLogs).toHaveLength(1);
+
+      const bobLogs = historyService.getByRecipient('bob@example.com');
+      expect(bobLogs).toHaveLength(1);
+    });
+
+    it('should track both sent and skipped notifications in history', async () => {
+      const user = makeUser();
+
+      // First: send successfully
+      await eventBus.emit<UserCreatedEvent>({
+        type: 'user:created',
+        user,
+        timestamp: new Date(),
+      });
+
+      // Now disable email and try again
+      preferencesService.updatePreferences(user.id, { emailEnabled: false });
+      await eventBus.emit<OrderCreatedEvent>({
+        type: 'order:created',
+        order: makeOrder(),
+        user,
+        timestamp: new Date(),
+      });
+
+      const logs = historyService.getAll();
+      expect(logs).toHaveLength(2);
+
+      expect(historyService.count('sent')).toBe(1);
+      expect(historyService.count('skipped')).toBe(1);
+    });
+
+    it('should query history by channel across different adapters', async () => {
+      // Send email via event
+      await eventBus.emit<UserCreatedEvent>({
+        type: 'user:created',
+        user: makeUser(),
+        timestamp: new Date(),
+      });
+
+      // Send SMS directly
+      await notificationService.sendNotification(
+        'order-confirmation',
+        {
+          recipient: '+15559876543',
+          subject: 'Order Placed',
+          body: 'Your order is confirmed.',
+          channel: 'sms',
+          priority: 'normal',
+        },
+        'user-1',
+      );
+
+      const emailLogs = historyService.query({ channel: 'email' });
+      expect(emailLogs).toHaveLength(1);
+
+      const smsLogs = historyService.query({ channel: 'sms' });
+      expect(smsLogs).toHaveLength(1);
+
+      expect(historyService.getAll()).toHaveLength(2);
+    });
+  });
+
+  // =========================================================
+  // 6. Notification ordering
+  // =========================================================
+
+  describe('notification ordering', () => {
+    it('should deliver notifications in order for the same recipient across events', async () => {
+      const user = makeUser();
+
+      // Fire order:created then order:status-changed in sequence
+      await eventBus.emit<OrderCreatedEvent>({
+        type: 'order:created',
+        order: makeOrder(),
+        user,
+        timestamp: new Date(),
+      });
+      await eventBus.emit<OrderStatusChangedEvent>({
+        type: 'order:status-changed',
+        order: makeOrder({ status: 'confirmed', userId: 'alice@example.com' }),
+        previousStatus: 'pending',
+        newStatus: 'confirmed',
+        timestamp: new Date(),
+      });
+
+      const notifications = notificationService.getNotifications();
+      expect(notifications).toHaveLength(2);
+      expect(notifications[0]?.type).toBe('order-confirmation');
+      expect(notifications[1]?.type).toBe('order-status-update');
+
+      // History should reflect the same order
+      const logs = historyService.getAll();
+      expect(logs).toHaveLength(2);
+      expect(logs[0]?.type).toBe('order-confirmation');
+      expect(logs[1]?.type).toBe('order-status-update');
+    });
+
+    it('should maintain order in history log IDs', async () => {
+      const user = makeUser();
+
+      await eventBus.emit<UserCreatedEvent>({
+        type: 'user:created',
+        user,
+        timestamp: new Date(),
+      });
+      await eventBus.emit<OrderCreatedEvent>({
+        type: 'order:created',
+        order: makeOrder(),
+        user,
+        timestamp: new Date(),
+      });
+
+      const logs = historyService.getAll();
+      expect(logs).toHaveLength(2);
+      // Log IDs should be sequential
+      expect(logs[0]?.id).toBe('log-0001');
+      expect(logs[1]?.id).toBe('log-0002');
+    });
+  });
+
+  // =========================================================
+  // 7. Multi-channel pipeline
+  // =========================================================
+
+  describe('multi-channel pipeline', () => {
+    it('should deliver to multiple channels for the same logical event', async () => {
+      const user = makeUser();
+
+      // Email via event
+      await eventBus.emit<OrderCreatedEvent>({
+        type: 'order:created',
+        order: makeOrder(),
+        user,
+        timestamp: new Date(),
+      });
+
+      // SMS for the same event type
+      await notificationService.sendNotification(
+        'order-confirmation',
+        {
+          recipient: '+15559876543',
+          subject: 'Order Confirmation: order-1',
+          body: 'Your order has been placed.',
+          channel: 'sms',
+          priority: 'normal',
+        },
+        'user-1',
+      );
+
+      // Webhook for the same event type
+      await notificationService.sendNotification(
+        'order-confirmation',
+        {
+          recipient: 'system-hook',
+          subject: 'Order Confirmation: order-1',
+          body: 'New order placed.',
+          channel: 'webhook',
+          priority: 'normal',
+          metadata: { orderId: 'order-1' },
+        },
+        'user-1',
+      );
+
+      // Verify all three channels received deliveries
+      expect(emailTransport.getInbox()).toHaveLength(1);
+      expect(smsTransport.getSent()).toHaveLength(1);
+      expect(webhookTransport.getRequests()).toHaveLength(1);
+
+      // History should contain all three
+      const logs = historyService.getAll();
+      expect(logs).toHaveLength(3);
+
+      const channels = logs.map((l) => l.channel);
+      expect(channels).toContain('email');
+      expect(channels).toContain('sms');
+      expect(channels).toContain('webhook');
+    });
+
+    it('should independently gate each channel via preferences', async () => {
+      preferencesService.updatePreferences('user-1', {
+        emailEnabled: true,
+        channelEnabled: { sms: false, webhook: true },
+      });
+
+      // Email: should send
+      await eventBus.emit<UserCreatedEvent>({
+        type: 'user:created',
+        user: makeUser(),
+        timestamp: new Date(),
+      });
+
+      // SMS: should be blocked
+      await notificationService.sendNotification(
+        'user-welcome',
+        {
+          recipient: '+15559876543',
+          subject: 'Welcome',
+          body: 'Welcome!',
+          channel: 'sms',
+          priority: 'normal',
+        },
+        'user-1',
+      );
+
+      // Webhook: should send
+      await notificationService.sendNotification(
+        'user-welcome',
+        {
+          recipient: 'system-hook',
+          subject: 'Welcome',
+          body: 'New user registered.',
+          channel: 'webhook',
+          priority: 'normal',
+        },
+        'user-1',
+      );
+
+      expect(emailTransport.getInbox()).toHaveLength(1);
+      expect(smsTransport.getSent()).toHaveLength(0);
+      expect(webhookTransport.getRequests()).toHaveLength(1);
+
+      // History: 2 sent + 1 skipped
+      expect(historyService.count('sent')).toBe(2);
+      expect(historyService.count('skipped')).toBe(1);
+    });
+  });
+});

