import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { PreferencesService } from '../../src/services/preferences.service.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { EmailAdapter, InMemoryTransport } from '../../src/adapters/email.adapter.js';
import { SmsAdapter, InMemorySmsTransport } from '../../src/adapters/sms.adapter.js';
import {
  WebhookAdapter,
  InMemoryWebhookTransport,
} from '../../src/adapters/webhook.adapter.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
} from '../../src/events/event-types.js';

/**
 * Integration tests for the full notification pipeline.
 *
 * These tests wire up the complete stack:
 *   EventBus → NotificationService → Adapters (email/sms/webhook)
 *                                   → PreferencesService
 *                                   → NotificationHistoryService
 *
 * Unlike unit tests, nothing is mocked — we use the in-memory transports
 * provided by each adapter to verify actual delivery.
 */
describe('Notification Pipeline Integration', () => {
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;
  let historyService: NotificationHistoryService;
  let emailTransport: InMemoryTransport;
  let smsTransport: InMemorySmsTransport;
  let webhookTransport: InMemoryWebhookTransport;

  beforeEach(() => {
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    preferencesService = new PreferencesService();
    historyService = new NotificationHistoryService();
    resetNotificationIdCounter();
    resetLogIdCounter();

    // Wire up preferences and history
    notificationService.setPreferencesService(preferencesService);
    notificationService.setHistoryService(historyService);

    // Set up email adapter with in-memory transport
    emailTransport = new InMemoryTransport();
    const emailAdapter = new EmailAdapter(
      { from: 'noreply@taskflow.com', appName: 'TaskFlow Pro' },
      emailTransport,
    );
    notificationService.registerAdapter(emailAdapter);

    // Set up SMS adapter with in-memory transport
    smsTransport = new InMemorySmsTransport();
    const smsAdapter = new SmsAdapter(
      { fromNumber: '+15551234567' },
      smsTransport,
    );
    notificationService.registerAdapter(smsAdapter);

    // Set up webhook adapter with in-memory transport
    webhookTransport = new InMemoryWebhookTransport();
    const webhookAdapter = new WebhookAdapter(
      { url: 'https://hooks.example.com/notify', secret: 'test-secret' },
      webhookTransport,
    );
    notificationService.registerAdapter(webhookAdapter);
  });

  // -- Helpers --

  function makeUser(overrides?: Partial<OrderCreatedEvent['user']>) {
    return {
      id: 'user-1',
