    return {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
      status: 'pending' as const,
      createdAt: new Date(),
      updatedAt: new Date(),
      ...overrides,
    };
  }

  // =========================================================
