  // =========================================================
  // 2. SMS channel — end-to-end via direct send
  // =========================================================

  describe('SMS channel end-to-end', () => {
    it('should deliver SMS notification to user with SMS preferences enabled', async () => {
      preferencesService.updatePreferences('user-1', {
        channelEnabled: { sms: true },
      });

      await notificationService.sendNotification(
        'order-confirmation',
